const MOD = 998244353;
function fast(n,m,a) {
  const indeg=Array(n).fill(0);
  for (const p of a) indeg[p]++;
  const q=[]; let head=0;
  for(let i=0;i<n;i++) if(indeg[i]===0) q.push(i);
  const removed=Array(n).fill(false), dp=Array(n).fill(null);
  while(head<q.length){
    const v=q[head++]; removed[v]=true; const p=a[v];
    const child=dp[v]; dp[v]=null;
    if(dp[p]===null) dp[p]=Array(m).fill(1);
    let pref=0;
    for(let k=0;k<m;k++){
      pref=(pref+(child===null?1:child[k]))%MOD;
      dp[p][k]=Number(BigInt(dp[p][k])*BigInt(pref)%BigInt(MOD));
    }
    if(--indeg[p]===0) q.push(p);
  }
  let ans=1; const seen=Array(n).fill(false);
  for(let s=0;s<n;s++) if(!removed[s]&&!seen[s]){
    const cyc=[]; let v=s;
    while(!seen[v]) {seen[v]=true;cyc.push(v);v=a[v];}
    let count=0;
    for(let k=0;k<m;k++){
      let ways=1;
      for(const u of cyc) if(dp[u]!==null)
        ways=Number(BigInt(ways)*BigInt(dp[u][k])%BigInt(MOD));
      count=(count+ways)%MOD;
    }
    ans=Number(BigInt(ans)*BigInt(count)%BigInt(MOD));
  }
  return ans;
}
function brute(n,m,a){
  let ans=0;
  const x=Array(n).fill(1);
  function go(i){
    if(i===n){
      for(let j=0;j<n;j++) if(x[j]>x[a[j]]) return;
      ans++; return;
    }
    for(let k=1;k<=m;k++){x[i]=k;go(i+1);}
  }
  go(0); return ans;
}
const samples=[
 [3,3,[1,0,0],6],
 [4,9,[0,0,0,0],2025],
 [10,5,[8,3,4,4,3,1,0,4,6,1],10010]
];
for(const [n,m,a,w] of samples){
  const got=fast(n,m,a);
  if(got!==w) throw new Error(`sample got ${got} expected ${w}`);
}
let seed=123456789;
function rnd(n){seed=(seed*1103515245+12345)>>>0; return seed%n;}
let checked=0;
for(let n=1;n<=7;n++) for(let m=1;m<=4;m++) for(let z=0;z<150;z++){
  const a=Array.from({length:n},()=>rnd(n));
  const f=fast(n,m,a), b=brute(n,m,a);
  if(f!==b) throw new Error(`mismatch n=${n} m=${m} a=${a} fast=${f} brute=${b}`);
  checked++;
}
